// Автосгенерировано из public/index.html — страница, встроенная в функцию.
// Обновить: npm run build:frontend
module.exports = "<!DOCTYPE html>\n<html lang=\"ru\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1.0\">\n<title>Almaty Clinic · Психологический скрининг</title>\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n<link href=\"https://fonts.googleapis.com/css2?family=Spectral:ital,wght@0,400;0,500;0,600;1,400&family=Manrope:wght@400;500;600;700;800&display=swap\" rel=\"stylesheet\">\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js\"></script>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js\"></script>\n<style>\n:root{\n  --bg:#EAF0EE; --surface:#FFFFFF; --surface-2:#F3F7F5;\n  --ink:#16302B; --ink-soft:#4E645E; --ink-faint:#8298916b;\n  --line:#D8E3DF;\n  --primary:#0E6E63; --primary-deep:#0A4D45; --primary-soft:#DCEBE6;\n  --sage:#6FA593;\n  --calm:#5C917F;      /* норма */\n  --amber:#C68A3E;     /* субклинически / лёгкая */\n  --clay:#B05B47;      /* клинически / тяжёлая */\n  --shadow:0 1px 2px rgba(16,48,43,.05),0 8px 30px rgba(16,48,43,.07);\n  --radius:18px;\n}\n*{box-sizing:border-box;-webkit-tap-highlight-color:transparent}\nhtml,body{margin:0;padding:0}\nbody{\n  font-family:'Manrope',system-ui,sans-serif;\n  background:\n    radial-gradient(120% 90% at 100% 0%, #F0F5F3 0%, transparent 55%),\n    radial-gradient(110% 80% at 0% 100%, #E4EEEA 0%, transparent 50%),\n    var(--bg);\n  color:var(--ink); min-height:100vh; line-height:1.5;\n  -webkit-font-smoothing:antialiased;\n}\n.wrap{max-width:600px;margin:0 auto;padding:0 18px 64px}\n\n/* Top bar */\n.topbar{\n  position:sticky;top:0;z-index:40;\n  display:flex;align-items:center;justify-content:space-between;gap:12px;\n  padding:14px 18px;margin:0 -18px 8px;\n  background:rgba(234,240,238,.82);backdrop-filter:blur(10px);\n  border-bottom:1px solid var(--line);\n}\n.brand{display:flex;align-items:center;gap:10px;font-weight:800;font-size:15px;letter-spacing:-.01em}\n.brand .dot{width:26px;height:26px;border-radius:8px;background:linear-gradient(150deg,var(--primary),var(--primary-deep));\n  display:grid;place-items:center;color:#fff;font-family:'Spectral',serif;font-weight:600}\n.langtoggle{display:inline-flex;background:var(--surface);border:1px solid var(--line);border-radius:999px;padding:3px;box-shadow:var(--shadow)}\n.langtoggle button{border:0;background:none;font:inherit;font-weight:700;font-size:13px;color:var(--ink-soft);\n  padding:6px 13px;border-radius:999px;cursor:pointer;transition:.18s}\n.langtoggle button.on{background:var(--primary);color:#fff}\n\n/* Screens */\n.screen{display:none;animation:rise .4s cubic-bezier(.2,.7,.2,1) both}\n.screen.active{display:block}\n@keyframes rise{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:none}}\n@media(prefers-reduced-motion:reduce){*{animation:none!important;transition:none!important}}\n\n.card{background:var(--surface);border:1px solid var(--line);border-radius:var(--radius);box-shadow:var(--shadow);padding:26px}\n.card + .card{margin-top:14px}\n\n.eyebrow{font-size:12px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:var(--primary)}\nh1{font-family:'Spectral',serif;font-weight:600;font-size:30px;line-height:1.12;letter-spacing:-.01em;margin:.35em 0 .3em}\nh2{font-family:'Spectral',serif;font-weight:600;font-size:22px;margin:0 0 6px;letter-spacing:-.01em}\n.lead{color:var(--ink-soft);font-size:15.5px;margin:0}\n.muted{color:var(--ink-soft);font-size:13.5px}\n\n/* Welcome */\n.hero{text-align:left;padding:34px 26px 30px;position:relative;overflow:hidden}\n.hero .glyph{font-family:'Spectral',serif;font-size:120px;line-height:1;color:var(--primary-soft);position:absolute;right:-6px;top:-22px;user-select:none}\n.qrnote{display:flex;gap:12px;align-items:flex-start;background:var(--surface-2);border:1px solid var(--line);\n  border-radius:14px;padding:14px 16px;margin-top:18px}\n.qrnote svg{flex:none;margin-top:2px}\n\n/* Buttons */\n.btn{display:inline-flex;align-items:center;justify-content:center;gap:9px;width:100%;\n  font:inherit;font-weight:700;font-size:16px;border:0;border-radius:14px;padding:15px 20px;cursor:pointer;transition:.16s}\n.btn.primary{background:var(--primary);color:#fff;box-shadow:0 6px 16px rgba(14,110,99,.28)}\n.btn.primary:hover{background:var(--primary-deep)}\n.btn.ghost{background:var(--surface);color:var(--ink);border:1px solid var(--line)}\n.btn.ghost:hover{background:var(--surface-2)}\n.btn:disabled{opacity:.45;cursor:not-allowed;box-shadow:none}\n.btnrow{display:flex;gap:10px;margin-top:6px}\n.btnrow .btn{width:auto;flex:1}\n.linkbtn{background:none;border:0;color:var(--primary);font:inherit;font-weight:700;font-size:13.5px;cursor:pointer;padding:8px;text-decoration:underline;text-underline-offset:3px}\n\n/* Form */\n.field{margin-bottom:16px}\n.field label{display:block;font-weight:700;font-size:13.5px;margin-bottom:7px}\n.field input{width:100%;font:inherit;font-size:16px;padding:13px 15px;border:1.5px solid var(--line);border-radius:12px;background:var(--surface-2);color:var(--ink);transition:.16s}\n.field input:focus{outline:none;border-color:var(--primary);background:#fff;box-shadow:0 0 0 4px var(--primary-soft)}\n.field .hint{font-size:12px;color:var(--ink-soft);margin-top:6px}\n.field.bad input{border-color:var(--clay);background:#fbeeeb}\n.field .err{display:none;color:var(--clay);font-size:12.5px;font-weight:600;margin-top:6px}\n.field.bad .err{display:block}\n\n/* Consent */\n.check{display:flex;gap:13px;align-items:flex-start;padding:15px;border:1.5px solid var(--line);border-radius:14px;cursor:pointer;margin-bottom:12px;transition:.16s;background:var(--surface-2)}\n.check:hover{border-color:var(--sage)}\n.check.on{border-color:var(--primary);background:var(--primary-soft)}\n.check input{margin-top:3px;width:20px;height:20px;accent-color:var(--primary);flex:none}\n.check .ctxt{font-size:14px;color:var(--ink);line-height:1.45}\n.consent-body{max-height:180px;overflow:auto;font-size:13px;color:var(--ink-soft);background:var(--surface-2);border:1px solid var(--line);border-radius:12px;padding:14px 16px;margin:14px 0}\n\n/* Progress */\n.progress{position:sticky;top:64px;z-index:30;margin:0 -18px 14px;padding:12px 18px;background:rgba(234,240,238,.9);backdrop-filter:blur(8px)}\n.progress .meta{display:flex;justify-content:space-between;font-size:12.5px;font-weight:700;color:var(--ink-soft);margin-bottom:7px}\n.pbar{height:7px;border-radius:99px;background:var(--line);overflow:hidden}\n.pbar>i{display:block;height:100%;background:linear-gradient(90deg,var(--sage),var(--primary));border-radius:99px;transition:width .35s cubic-bezier(.2,.7,.2,1)}\n.stagechip{display:inline-flex;align-items:center;gap:6px;font-size:11.5px;font-weight:800;letter-spacing:.03em;color:var(--primary);background:var(--primary-soft);padding:4px 10px;border-radius:99px}\n\n/* Question */\n.q{padding:22px}\n.q .qnum{font-family:'Spectral',serif;font-size:13px;color:var(--sage);font-weight:600}\n.q .qtext{font-family:'Spectral',serif;font-size:19px;line-height:1.35;margin:4px 0 16px;color:var(--ink)}\n.opt{display:flex;gap:12px;align-items:center;padding:13px 15px;border:1.5px solid var(--line);border-radius:13px;cursor:pointer;margin-bottom:9px;transition:.14s;background:var(--surface)}\n.opt:hover{border-color:var(--sage);background:var(--surface-2)}\n.opt.on{border-color:var(--primary);background:var(--primary-soft)}\n.opt .radio{width:20px;height:20px;border-radius:50%;border:2px solid var(--line);flex:none;display:grid;place-items:center;transition:.14s}\n.opt.on .radio{border-color:var(--primary)}\n.opt.on .radio::after{content:\"\";width:10px;height:10px;border-radius:50%;background:var(--primary)}\n.opt .otxt{font-size:14.5px;line-height:1.35}\n\n/* Result */\n.scorehead{text-align:center;padding:30px 26px}\n.gauge{margin:20px 0 6px}\n.gauge .track{position:relative;height:14px;border-radius:99px;display:flex;overflow:hidden;border:1px solid var(--line)}\n.gauge .track>span{height:100%}\n.gauge .marker{position:absolute;top:-9px;width:4px;height:32px;background:var(--ink);border-radius:99px;transform:translateX(-50%);box-shadow:0 0 0 3px #fff}\n.gauge .scalelabels{display:flex;justify-content:space-between;font-size:11px;color:var(--ink-soft);margin-top:8px;font-weight:600}\n.pill{display:inline-flex;align-items:center;gap:7px;font-weight:800;font-size:13px;padding:6px 13px;border-radius:99px}\n.resultrow{display:flex;justify-content:space-between;align-items:center;gap:12px;padding:16px 0;border-bottom:1px solid var(--line)}\n.resultrow:last-child{border-bottom:0}\n.resultrow .lbl{font-size:14px;font-weight:700}\n.resultrow .sub{font-size:12px;color:var(--ink-soft)}\n.bignum{font-family:'Spectral',serif;font-weight:600;font-size:40px;line-height:1}\n.notice{display:flex;gap:12px;background:#fbf2ec;border:1px solid #edd3c2;border-radius:14px;padding:15px 16px;margin-top:16px}\n.notice.calm{background:var(--surface-2);border-color:var(--line)}\n.notice .ntxt{font-size:13.5px;color:var(--ink)}\n.notice strong{color:var(--clay)}\n\n/* Doctor */\n.statgrid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:16px}\n.stat{background:var(--surface-2);border:1px solid var(--line);border-radius:14px;padding:14px}\n.stat .n{font-family:'Spectral',serif;font-size:26px;font-weight:600}\n.stat .k{font-size:11.5px;color:var(--ink-soft);font-weight:600}\n.tablewrap{overflow:auto;border:1px solid var(--line);border-radius:14px;margin-top:6px}\ntable{width:100%;border-collapse:collapse;font-size:12.5px;min-width:560px}\nth,td{text-align:left;padding:10px 12px;border-bottom:1px solid var(--line);white-space:nowrap}\nth{background:var(--surface-2);font-weight:800;color:var(--ink-soft);position:sticky;top:0}\ntd .tag{font-size:10.5px;font-weight:800;padding:2px 8px;border-radius:99px}\n.empty{text-align:center;color:var(--ink-soft);padding:40px 20px;font-size:14px}\n#qrbox{display:grid;place-items:center;padding:16px;background:#fff;border:1px solid var(--line);border-radius:14px;margin-top:10px}\n#qrbox img,#qrbox canvas{border-radius:6px}\n.footer{text-align:center;color:var(--ink-soft);font-size:12px;margin-top:28px}\n.footer a{color:var(--primary)}\n</style>\n</head>\n<body>\n\n<div class=\"topbar\">\n  <div class=\"brand\"><span class=\"dot\">A</span><span><span style=\"display:block;line-height:1.05\">Almaty Clinic</span><span style=\"display:block;font-size:10.5px;font-weight:600;color:var(--ink-soft);letter-spacing:.02em\" data-t=\"brand_sub\">Психологическая служба</span></span></div>\n  <div class=\"langtoggle\">\n    <button id=\"lang-ru\" class=\"on\" onclick=\"setLang('ru')\">РУС</button>\n    <button id=\"lang-kz\" onclick=\"setLang('kz')\">ҚАЗ</button>\n  </div>\n</div>\n\n<div class=\"wrap\">\n\n  <!-- WELCOME -->\n  <section id=\"s-welcome\" class=\"screen active\">\n    <div class=\"card hero\">\n      <span class=\"glyph\">Ψ</span>\n      <span class=\"eyebrow\" data-t=\"wl_eyebrow\">Almaty Clinic · двухэтапный скрининг</span>\n      <h1 data-t=\"wl_title\">Оценка тревоги и депрессии у студентов</h1>\n      <p class=\"lead\" data-t=\"wl_lead\">Первый этап — шкала HADS. Если по шкале тревоги или депрессии набрано 9 баллов и более, автоматически подключается второй этап — шкала депрессии Бека.</p>\n      <div class=\"qrnote\">\n        <svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#0E6E63\" stroke-width=\"2\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/><path d=\"M14 14h3v3M20 14v.01M14 20h.01M20 20h.01M17 20v.01M20 17h.01\"/></svg>\n        <div class=\"muted\" data-t=\"wl_qr\">Вход выполнен по QR-коду. Тестирование анонимно для других студентов; результаты видит только психолог.</div>\n      </div>\n    </div>\n    <div class=\"card\">\n      <button class=\"btn primary\" onclick=\"go('register')\"><span data-t=\"wl_start\">Начать тестирование</span> →</button>\n      <div style=\"text-align:center;margin-top:12px;display:flex;flex-direction:column;gap:8px\">\n        <button class=\"linkbtn\" onclick=\"showEntryQR()\" data-t=\"wl_showqr\">Показать QR для входа</button>\n        <button class=\"linkbtn\" onclick=\"openDoctor()\" data-t=\"wl_doctor\">Кабинет психолога</button>\n      </div>\n    </div>\n    <p class=\"footer muted\" data-t=\"wl_foot\">Инструмент скрининга. Не является клиническим диагнозом — интерпретирует специалист.</p>\n  </section>\n\n  <!-- REGISTER -->\n  <section id=\"s-register\" class=\"screen\">\n    <div class=\"card\">\n      <span class=\"eyebrow\" data-t=\"rg_eyebrow\">Идентификация</span>\n      <h2 data-t=\"rg_title\">Ваши данные</h2>\n      <p class=\"muted\" style=\"margin:0 0 18px\" data-t=\"rg_lead\">Данные нужны психологу для обратной связи. Заполните все поля.</p>\n\n      <div class=\"field\" id=\"f-vuz\">\n        <label data-t=\"rg_vuz\">ВУЗ</label>\n        <input id=\"in-vuz\" type=\"text\" data-tph=\"rg_vuz_ph\" placeholder=\"Название учебного заведения\" autocomplete=\"organization\">\n        <div class=\"err\" data-t=\"rg_req\">Заполните поле</div>\n      </div>\n      <div class=\"field\" id=\"f-fio\">\n        <label data-t=\"rg_fio\">ФИО</label>\n        <input id=\"in-fio\" type=\"text\" data-tph=\"rg_fio_ph\" placeholder=\"Фамилия Имя Отчество\" autocomplete=\"name\">\n        <div class=\"err\" data-t=\"rg_req\">Заполните поле</div>\n      </div>\n      <div class=\"field\" id=\"f-iin\">\n        <label data-t=\"rg_iin\">ИИН</label>\n        <input id=\"in-iin\" type=\"text\" inputmode=\"numeric\" maxlength=\"12\" placeholder=\"12 цифр\">\n        <div class=\"hint\" data-t=\"rg_iin_hint\">Индивидуальный идентификационный номер — 12 цифр.</div>\n        <div class=\"err\" data-t=\"rg_iin_err\">ИИН должен содержать ровно 12 цифр</div>\n      </div>\n\n      <div class=\"btnrow\">\n        <button class=\"btn ghost\" onclick=\"go('welcome')\" data-t=\"back\">Назад</button>\n        <button class=\"btn primary\" onclick=\"submitRegister()\" data-t=\"next\">Далее</button>\n      </div>\n    </div>\n  </section>\n\n  <!-- CONSENT -->\n  <section id=\"s-consent\" class=\"screen\">\n    <div class=\"card\">\n      <span class=\"eyebrow\" data-t=\"cn_eyebrow\">Согласие</span>\n      <h2 data-t=\"cn_title\">Согласие на обработку данных и тестирование</h2>\n      <div class=\"consent-body\" data-t=\"cn_body\">Я даю согласие на сбор, хранение и обработку моих персональных данных (ВУЗ, ФИО, ИИН) в целях психологического сопровождения. Данные обрабатываются психологической службой учебного заведения и не передаются третьим лицам без моего согласия, за исключением случаев, предусмотренных законодательством. Я подтверждаю, что ознакомлен(а) с целью тестирования и даю согласие на его прохождение добровольно.</div>\n\n      <label class=\"check\" id=\"chk1-wrap\" onclick=\"toggleChk(1)\">\n        <input type=\"checkbox\" id=\"chk1\" onclick=\"event.stopPropagation();toggleChk(1)\">\n        <span class=\"ctxt\" data-t=\"cn_c1\">Согласие на сбор, хранение и обработку персональных данных</span>\n      </label>\n      <label class=\"check\" id=\"chk2-wrap\" onclick=\"toggleChk(2)\">\n        <input type=\"checkbox\" id=\"chk2\" onclick=\"event.stopPropagation();toggleChk(2)\">\n        <span class=\"ctxt\" data-t=\"cn_c2\">Согласие на прохождение психологического тестирования</span>\n      </label>\n\n      <div class=\"btnrow\">\n        <button class=\"btn ghost\" onclick=\"go('register')\" data-t=\"back\">Назад</button>\n        <button class=\"btn primary\" id=\"consent-next\" disabled onclick=\"startTest()\" data-t=\"cn_start\">Приступить к тесту</button>\n      </div>\n    </div>\n  </section>\n\n  <!-- TEST -->\n  <section id=\"s-test\" class=\"screen\">\n    <div class=\"progress\">\n      <div class=\"meta\">\n        <span class=\"stagechip\"><span id=\"stage-label\">HADS · Этап 1</span></span>\n        <span id=\"q-counter\">1 / 14</span>\n      </div>\n      <div class=\"pbar\"><i id=\"pbar-fill\" style=\"width:7%\"></i></div>\n    </div>\n    <div class=\"card q\" id=\"q-card\"><!-- rendered --></div>\n    <div class=\"btnrow\">\n      <button class=\"btn ghost\" id=\"q-back\" onclick=\"prevQ()\" data-t=\"back\">Назад</button>\n      <button class=\"btn primary\" id=\"q-next\" onclick=\"nextQ()\" data-t=\"next\">Далее</button>\n    </div>\n  </section>\n\n  <!-- RESULT -->\n  <section id=\"s-result\" class=\"screen\">\n    <div class=\"card scorehead\" id=\"result-head\"></div>\n    <div class=\"card\" id=\"result-detail\"></div>\n    <div class=\"card\">\n      <button class=\"btn primary\" onclick=\"finishToWelcome()\" data-t=\"rs_finish\">Завершить</button>\n      <div style=\"text-align:center;margin-top:12px\">\n        <button class=\"linkbtn\" onclick=\"openDoctor()\" data-t=\"wl_doctor\">Кабинет психолога</button>\n      </div>\n    </div>\n  </section>\n\n  <!-- DOCTOR -->\n  <section id=\"s-doctor\" class=\"screen\">\n    <div class=\"card\">\n      <span class=\"eyebrow\" data-t=\"dc_eyebrow\">Служебный раздел</span>\n      <h2 data-t=\"dc_title\">Кабинет психолога</h2>\n      <div class=\"statgrid\">\n        <div class=\"stat\"><div class=\"n\" id=\"st-total\">0</div><div class=\"k\" data-t=\"dc_total\">Всего</div></div>\n        <div class=\"stat\"><div class=\"n\" id=\"st-stage2\">0</div><div class=\"k\" data-t=\"dc_stage2\">На 2 этапе</div></div>\n        <div class=\"stat\"><div class=\"n\" id=\"st-flag\">0</div><div class=\"k\" data-t=\"dc_flag\">Требуют внимания</div></div>\n      </div>\n      <div class=\"btnrow\">\n        <button class=\"btn primary\" onclick=\"exportExcel()\">↓ Excel</button>\n        <button class=\"btn ghost\" onclick=\"go('welcome')\" data-t=\"dc_exit\">Выйти</button>\n      </div>\n      <div style=\"margin-top:10px\"><button class=\"linkbtn\" onclick=\"clearAll()\" data-t=\"dc_clear\">Очистить все записи</button></div>\n    </div>\n\n    <div class=\"card\">\n      <h2 style=\"font-size:18px\" data-t=\"dc_records\">Записи</h2>\n      <div id=\"doc-table\"></div>\n    </div>\n\n    <div class=\"card\">\n      <h2 style=\"font-size:18px\" data-t=\"dc_qr\">QR-код для входа</h2>\n      <p class=\"muted\" data-t=\"dc_qr_lead\">Разместите приложение на хостинге и покажите этот код студентам — он ведёт на текущий адрес страницы.</p>\n      <div id=\"qrbox\"></div>\n    </div>\n  </section>\n\n  <!-- ENTRY QR -->\n  <section id=\"s-qr\" class=\"screen\">\n    <div class=\"card\" style=\"text-align:center\">\n      <span class=\"eyebrow\" data-t=\"qr_eyebrow\">Вход по QR</span>\n      <h2 data-t=\"qr_title\">Наведите камеру телефона на код</h2>\n      <p class=\"muted\" data-t=\"qr_lead\">Код ведёт на адрес этого приложения. Покажите его студентам (на экране или распечатайте) — они сканируют камерой и попадают на тест.</p>\n      <div id=\"entry-qrbox\" style=\"display:grid;place-items:center;padding:18px;background:#fff;border:1px solid var(--line);border-radius:14px;margin:14px 0\"></div>\n      <p class=\"muted\" id=\"entry-qr-url\" style=\"word-break:break-all;font-size:12px\"></p>\n      <button class=\"btn ghost\" onclick=\"go('welcome')\" data-t=\"back\">Назад</button>\n    </div>\n  </section>\n\n</div>\n\n<script>\n/* ================= ДАННЫЕ МЕТОДИК ================= */\nconst HADS_STAGE2_THRESHOLD = 9; // ≥9 по любой шкале → 2 этап (по ТЗ)\n\n/* HADS — Депрессия (Часть I). score = баллы, порядок = как в бланке */\nconst HADS_DEP = [\n {q:{ru:\"То, что приносило мне большое удовольствие, и сейчас вызывает у меня такое же чувство\",kz:\"Маған бұрын үлкен рахат әкелген нәрселер, қазір де осындай рахат сезім әкеледі\"},\n  o:[{ru:\"определённо, это так\",kz:\"әрине, бұл сөзсіз солай\",s:0},{ru:\"наверное, это так\",kz:\"мүмкін солай шығар\",s:1},{ru:\"лишь в очень малой степени это так\",kz:\"бұл кейбір кезде ғана\",s:2},{ru:\"это совсем не так\",kz:\"мүлдем олай емес\",s:3}]},\n {q:{ru:\"Я способен рассмеяться и увидеть в том или ином событии смешное\",kz:\"Мен әр түрлі болған оқиғалардан күлкілі нәрсені көріп күле аламын\"},\n  o:[{ru:\"определённо, это так\",kz:\"әрине, бұл сөзсіз солай\",s:0},{ru:\"наверное, это так\",kz:\"мүмкін солай шығар\",s:1},{ru:\"лишь в очень малой степени это так\",kz:\"бұл кейбір кезде ғана\",s:2},{ru:\"совсем не способен\",kz:\"мүлдем ондай қабілетім жоқ\",s:3}]},\n {q:{ru:\"Я испытываю бодрость\",kz:\"Мен сергектікті сезінемін\"},\n  o:[{ru:\"практически всё время\",kz:\"барлық уақытта дерлік солай\",s:0},{ru:\"иногда\",kz:\"кейде\",s:1},{ru:\"очень редко\",kz:\"өте сирек\",s:2},{ru:\"совсем не испытываю\",kz:\"мүлдем сергектік сезінбеймін\",s:3}]},\n {q:{ru:\"Мне кажется, что я стал всё делать очень медленно\",kz:\"Менің ойымша, мен баяу қимылдаймын\"},\n  o:[{ru:\"совсем нет\",kz:\"мүлдем жоқ\",s:0},{ru:\"иногда\",kz:\"кейде\",s:1},{ru:\"часто\",kz:\"жиі\",s:2},{ru:\"практически всё время\",kz:\"барлық уақытта дерлік солай\",s:3}]},\n {q:{ru:\"Я не слежу за своей внешностью\",kz:\"Мен сыртқы келбетіме көңіл бөлмеймін\"},\n  o:[{ru:\"я слежу за собой так же, как и раньше\",kz:\"мен оған бұрынғыдай уақыт бөлемін\",s:0},{ru:\"может быть, я стал меньше уделять этому времени\",kz:\"мүмкін мен оған аз уақыт бөлетін болған шығармын\",s:1},{ru:\"я не уделяю этому столько времени, сколько нужно\",kz:\"мен оған қажетті уақыт бөлмеймін\",s:2},{ru:\"определённо, это так\",kz:\"әрине, бұл сөзсіз солай\",s:3}]},\n {q:{ru:\"Я считаю, что мои дела (занятия, увлечения) могут принести мне чувство удовлетворения\",kz:\"Менің істерім (іс-әрекеттерім, қызығушылықтарым) маған қанағат сезімін әкелуі мүмкін деп санаймын\"},\n  o:[{ru:\"точно так же, как и обычно\",kz:\"тура әдеттегідей\",s:0},{ru:\"да, но не в той степени, как раньше\",kz:\"ия, бірақ бұрынғы дәрежедегідей емес\",s:1},{ru:\"значительно меньше, чем обычно\",kz:\"айтарлықтай, әдеттегіден аз\",s:2},{ru:\"совсем так не считаю\",kz:\"мүлдем олай санамаймын\",s:3}]},\n {q:{ru:\"Я могу получить удовольствие от хорошей книги, радио- или телепрограммы\",kz:\"Мен жақсы кітап, радио немесе теледидар бағдарламасынан ләззат ала аламын\"},\n  o:[{ru:\"часто\",kz:\"жиі\",s:0},{ru:\"иногда\",kz:\"кейде\",s:1},{ru:\"редко\",kz:\"сирек\",s:2},{ru:\"очень редко\",kz:\"өте сирек\",s:3}]},\n];\n\n/* HADS — Тревога (Часть II) */\nconst HADS_ANX = [\n {q:{ru:\"Я испытываю напряжение, мне не по себе\",kz:\"Мен мазасыздықты сезінемін, өзімді жайсыз сезінемін\"},\n  o:[{ru:\"совсем не испытываю\",kz:\"мүлдем сезбеймін\",s:0},{ru:\"время от времени, иногда\",kz:\"анда-санда, кейде\",s:1},{ru:\"часто\",kz:\"жиі\",s:2},{ru:\"всё время\",kz:\"үнемі\",s:3}]},\n {q:{ru:\"Я испытываю страх, кажется, что что-то ужасное может вот-вот случиться\",kz:\"Мен қорқынышты сезінемін, бір жаман нәрсе болып қалатын сияқты\"},\n  o:[{ru:\"совсем не испытываю\",kz:\"мен оны мүлдем сезбеймін\",s:0},{ru:\"иногда, но это меня не беспокоит\",kz:\"кейде, бірақ бұл мені алаңдатпайды\",s:1},{ru:\"да, это так, но страх не очень велик\",kz:\"ия, ол солай, бірақ қорқыныш сезімі онша үлкен емес\",s:2},{ru:\"определённо это так, и страх очень велик\",kz:\"бұл сөзсіз солай, қорқыныш сезімі өте жоғары\",s:3}]},\n {q:{ru:\"Беспокойные мысли крутятся у меня в голове\",kz:\"Басыма мазасыз ойлар келе береді\"},\n  o:[{ru:\"только иногда\",kz:\"тек кейде ғана\",s:0},{ru:\"время от времени и не так часто\",kz:\"анда-санда, жиі емес\",s:1},{ru:\"большую часть времени\",kz:\"уақыттың көп бөлігінде\",s:2},{ru:\"постоянно\",kz:\"үнемі\",s:3}]},\n {q:{ru:\"Я легко могу присесть и расслабиться\",kz:\"Мен отыра қалып, денемді оңай босаңсытып демала аламын\"},\n  o:[{ru:\"определённо, это так\",kz:\"әрине, ол солай\",s:0},{ru:\"наверно, это так\",kz:\"мүмкін солай шығар\",s:1},{ru:\"лишь изредка, это так\",kz:\"тек анда-санда солай\",s:2},{ru:\"совсем не могу\",kz:\"мүлдем олай істей алмаймын\",s:3}]},\n {q:{ru:\"Я испытываю внутреннее напряжение или дрожь\",kz:\"Мен ішкі мазасыздықты немесе дірілді сезінемін\"},\n  o:[{ru:\"совсем не испытываю\",kz:\"мүлдем сезбеймін\",s:0},{ru:\"иногда\",kz:\"кейде\",s:1},{ru:\"часто\",kz:\"жиі\",s:2},{ru:\"очень часто\",kz:\"өте жиі\",s:3}]},\n {q:{ru:\"Я испытываю неусидчивость, мне постоянно нужно двигаться\",kz:\"Мен бір орында отыра алмаймын, үнемі ары-бері жүре беремін\"},\n  o:[{ru:\"совсем не испытываю\",kz:\"мүлдем сезбеймін\",s:0},{ru:\"лишь в некоторой степени, это так\",kz:\"кейбір кездерде ғана\",s:1},{ru:\"наверно, это так\",kz:\"мүмкін солай шығар\",s:2},{ru:\"определённо, это так\",kz:\"әрине, ол солай\",s:3}]},\n {q:{ru:\"У меня бывает внезапное чувство паники\",kz:\"Менде кенеттен күйгелектік сезім пайда болады\"},\n  o:[{ru:\"совсем не бывает\",kz:\"мүлдем болмайды\",s:0},{ru:\"не так уж часто\",kz:\"анда-санда\",s:1},{ru:\"довольно часто\",kz:\"жиі\",s:2},{ru:\"очень часто\",kz:\"өте жиі\",s:3}]},\n];\n\n/* Шкала депрессии Бека (BDI) — 21 пункт, варианты 0..3 по порядку */\nconst BECK = [\n {ru:[\"Я не испытываю грусти.\",\"Мне грустно или тоскливо.\",\"Мне всё время тоскливо или грустно, и я не могу избавиться от этого чувства.\",\"Мне так грустно или печально, что это просто невыносимо.\"],\n  kz:[\"Мен өзімді мұңайып, қайғырып жүрген сияқты сезінбеймін.\",\"Мен мұңдымын.\",\"Мен үнемі мұңайып жүремін және одан арыла алмаймын.\",\"Мен қатты мұңайып, өзімді бақытсыз сезінгенім соншалық, бұған төзе алмаймын.\"]},\n {ru:[\"Мысли о будущем не вызывают у меня уныния и удручённости.\",\"Мне становится грустно, когда я думаю о будущем.\",\"Я чувствую, что от будущего мне ничего хорошего ожидать не стоит.\",\"Я считаю, что будущее безнадёжно и ничто в лучшую сторону измениться не может.\"],\n  kz:[\"Мен өз болашағыма алаңдамаймын.\",\"Мен өз болашағым туралы жиі алаңдаймын.\",\"Болашақта мені ешқандай жақсылық күтпейтіндей сезінемін.\",\"Менің болашағым үмітсіз және оны ештеңе жақсы жаққа өзгерте алмайды.\"]},\n {ru:[\"Я не считаю себя неудачником.\",\"Я считаю, что терпел неудачи чаще, чем средний человек.\",\"Когда я оглядываюсь на прожитую жизнь, то всё, что я вижу, — лишь цепь неудач.\",\"Я считаю, что как личность (родитель, муж, жена) потерпел полное поражение.\"],\n  kz:[\"Мен өзімді жолы болмаған адам деп сезінбеймін.\",\"Мен басқа адамдарға қарағанда өзімді көп сәтсіздікке ұшыраған адамдай сезінемін.\",\"Мен өз өміріме қарасам, көптеген сәтсіздіктерді көремін.\",\"Мен жеке тұлға ретінде өзімді нағыз жолы болмаған адам деп ойлаймын.\"]},\n {ru:[\"Я не испытываю никакой особой неудовлетворённости.\",\"Ничто не радует меня так, как прежде.\",\"Я больше ни от чего не получаю удовлетворения.\",\"Я недоволен и неудовлетворён всем.\"],\n  kz:[\"Мен өміріме бұрынғыдай ризамын.\",\"Мен өміріме бұрынғыдай көңілім толмайды.\",\"Қазір мені ештеңе қанағаттандырмайды.\",\"Мен өмірге толығымен қанағаттанбаймын және бәрінен шаршадым.\"]},\n {ru:[\"Я не чувствую себя в чём-либо виноватым.\",\"Я чувствую себя виноватым.\",\"Большую часть времени я чувствую себя плохим и никчёмным.\",\"Я чувствую себя очень скверным и ни к чему не годным человеком.\"],\n  kz:[\"Мен өзімді ештеңеге кінәлі сезінбеймін.\",\"Мен өзімді жиі кінәлі сезінемін.\",\"Көп жағдайда мен өзімді кінәлі сезінемін.\",\"Мен өзімді үнемі кінәлі сезінемін.\"]},\n {ru:[\"Я не считаю, что я наказан.\",\"У меня такое чувство, что что-то нехорошее может случиться со мной.\",\"Я считаю, что наказан или буду наказан.\",\"Я считаю, что заслуживаю наказания.\"],\n  kz:[\"Мен өзімді ешнәрсе үшін жазаланбайтындай сезінемін.\",\"Мен жазалануым мүмкін екенін сеземін.\",\"Мен жазалануым мүмкін деп күтемін.\",\"Мен қазірдің өзінде жазаланғандай сезінемін.\"]},\n {ru:[\"Я не испытываю разочарования в себе.\",\"Я разочарован в себе.\",\"Я испытываю отвращение к себе.\",\"Я ненавижу себя.\"],\n  kz:[\"Менің өзіме көңілім толады.\",\"Менің өзіме көңілім толмайды.\",\"Мен өзімнен жиіркенемін.\",\"Мен өзімді жек көремін.\"]},\n {ru:[\"Я не считаю, что я хуже других.\",\"Я осуждаю себя за свои слабости и ошибки.\",\"Я виноват во всём, что происходит не так, как хотелось бы.\",\"Я считаю, что у меня много серьёзных недостатков.\"],\n  kz:[\"Мен өзімді басқалардан кем санамаймын.\",\"Мен қателіктер мен әлсіздіктер үшін өзімді айыптаймын.\",\"Мен өз әрекеттерім үшін үнемі өзімді кінәлаймын.\",\"Мен болып жатқан барлық жамандыққа өзімді кінәлаймын.\"]},\n {ru:[\"У меня нет мыслей о том, чтобы причинить себе вред.\",\"У меня есть мысли причинить себе вред, но я их не осуществляю.\",\"Я считаю, что лучше было бы умереть.\",\"Я покончу с собой, как только появится такая возможность.\"],\n  kz:[\"Мен ешқашан өз-өзіме қол жұмсау туралы ойлаған емеспін.\",\"Маған өз-өзіме қол жұмсау туралы ойлар келеді, бірақ мен оны жүзеге асырмаймын.\",\"Мен өзімді өлтіргім келеді.\",\"Егер маған қолайлы сәт туса, мен қол жұмсаймын.\"]},\n {ru:[\"Я плачу не чаще, чем обычно.\",\"Я плачу чаще, чем обычно.\",\"Я плачу всё время и не могу остановиться.\",\"Раньше я плакал, но сейчас не могу плакать, даже если хочу.\"],\n  kz:[\"Мен әдеттегіден көп жыламаймын.\",\"Мен қазір бұрынғыға қарағанда жиі жылаймын.\",\"Қазір мен үнемі жылаймын.\",\"Бұрын мен жылайтынмын, ал қазір жылағым келсе де жылай алмаймын.\"]},\n {ru:[\"Я сейчас не более раздражителен, чем обычно.\",\"У меня сейчас легче, чем обычно, возникает раздражительность.\",\"Сейчас я постоянно чувствую раздражительность.\",\"Меня совсем не раздражает то, что обычно всегда раздражало.\"],\n  kz:[\"Мен қазір әдеттегіден де ашуланшақ емеспін.\",\"Мен бұрынғыға қарағанда тез ашуланып кетемін.\",\"Қазір мен өзімді үнемі ашулы сезінемін.\",\"Бұрын ашуымды шақыратын нәрселерге мен енді бей-жай қарай бастадым.\"]},\n {ru:[\"Я не утратил интереса к другим людям.\",\"Я меньше, чем бывало, интересуюсь другими людьми.\",\"Я почти утратил интерес к другим людям, у меня почти нет чувств к ним.\",\"Я полностью утратил интерес к другим людям, они меня совершенно не заботят.\"],\n  kz:[\"Мен басқа адамдарға деген қызығушылығымды жоғалтқан жоқпын.\",\"Мен бұрынғыға қарағанда басқа адамдарға онша қызығушылық танытпаймын.\",\"Мен басқа адамдарға деген қызығушылығымды жоғалттым.\",\"Менің басқа адамдарға деген қызығушылығым мүлдем жоқ.\"]},\n {ru:[\"Я принимаю решения примерно так же легко, как всегда.\",\"Я пытаюсь отложить принятие решений.\",\"Я больше не могу принимать решения без чьей-либо помощи.\",\"Я больше совсем не могу принимать решений.\"],\n  kz:[\"Мен шешімді бұрынғыдай оңай қабылдаймын.\",\"Мен шешім қабылдауды кейінге қалдыруға тырысамын.\",\"Маған бұрынғыдан гөрі қазір шешім қабылдау қиынырақ.\",\"Мен қазір мүлде шешім қабылдай алмаймын.\"]},\n {ru:[\"Я не считаю, что выгляжу сколько-нибудь хуже, чем обычно.\",\"Меня беспокоит, что я выгляжу старым и непривлекательным.\",\"Я чувствую, что внешне со мной происходят изменения, делающие меня непривлекательным.\",\"Я считаю, что выгляжу гадко и отталкивающе.\"],\n  kz:[\"Мен өзімді әдеттегіден нашар сезінбеймін.\",\"Мен кәрі және тартымсыз болып көрінемін деп алаңдаймын.\",\"Сыртқы келбетімде мені тартымсыз ететін елеулі өзгерістер болғанын білемін.\",\"Мен нашар көрінетінімді білемін.\"]},\n {ru:[\"Я могу работать почти так же хорошо, как и раньше.\",\"Мне нужно дополнительное усилие, чтобы что-нибудь сделать.\",\"Я с трудом заставляю себя делать что-либо.\",\"Я не могу выполнить никакую работу вообще.\"],\n  kz:[\"Мен бұрынғыдай жақсы жұмыс істей аламын.\",\"Бірдеңе жасауды бастау үшін маған қосымша күш салу қажет.\",\"Мен бір нәрсені өзімді мәжбүрлеп зорға жасаймын.\",\"Мен мүлдем ештеңе істей алмаймын.\"]},\n {ru:[\"Я сплю так же хорошо, как обычно.\",\"Я просыпаюсь утром менее отдохнувшим, чем обычно.\",\"Я просыпаюсь на 1–2 часа раньше обычного, и мне трудно снова уснуть.\",\"Я просыпаюсь рано каждый день и не могу спать более 5 часов.\"],\n  kz:[\"Мен бұрынғыдай жақсы ұйықтаймын.\",\"Мен қазір бұрынғыдан нашар ұйықтаймын.\",\"Мен 1–2 сағат бұрын оянамын, қайта ұйықтай алмай қиналамын.\",\"Мен әдеттегіден бірнеше сағат бұрын оянамын да, содан кейін мүлде ұйықтай алмаймын.\"]},\n {ru:[\"Я устаю ничуть не больше, чем обычно.\",\"Я устаю быстрее, чем обычно.\",\"Я устаю почти от любого занятия.\",\"Я слишком сильно устаю, чтобы чем-либо заниматься.\"],\n  kz:[\"Мен әдеттегіден көп шаршамаймын.\",\"Қазір мен бұрынғыдан тез шаршап қаламын.\",\"Мен барлық дерлік істерімнен шаршаймын.\",\"Мен шаршағандықтан ештеңе істей алмаймын.\"]},\n {ru:[\"Мой аппетит не хуже, чем обычно.\",\"Мой аппетит не такой хороший, как обычно.\",\"Мой аппетит гораздо хуже, чем обычно.\",\"У меня нет аппетита вообще.\"],\n  kz:[\"Менің тәбетім әдеттегіден жаман емес.\",\"Менің тәбетім бұрынғыдан нашарлады.\",\"Менің тәбетім қазір әлдеқайда нашар.\",\"Менде тәбет мүлде жоқ.\"]},\n {ru:[\"За последнее время я заметно не похудел.\",\"Я похудел более чем на 2 кг.\",\"Я похудел более чем на 5 кг.\",\"Я похудел более чем на 7 кг.\"],\n  kz:[\"Мен соңғы уақытта салмақ тастаған жоқпын немесе өте аз тастадым.\",\"Соңғы уақытта мен 2 келіден артық салмақ тастадым.\",\"Мен 5 келіден артық салмақ тастадым.\",\"Мен 7 келіден артық салмақ тастадым.\"]},\n {ru:[\"Я озабочен своим здоровьем не более, чем обычно.\",\"Меня беспокоят боли, расстройство желудка, запоры или другие неприятные ощущения в теле.\",\"Я настолько обеспокоен своим самочувствием, что мне трудно думать о чём-то другом.\",\"Я полностью поглощён тем, как я себя чувствую.\"],\n  kz:[\"Мен өз денсаулығыма әдеттегіден артық алаңдамаймын.\",\"Мені физикалық денсаулығым (ауырсыну, асқазан бұзылуы, іш қату, т.б.) мазалайды.\",\"Мен өзімнің физикалық жағдайыма қатты алаңдаймын, басқа нәрсе туралы ойлау қиын.\",\"Мен өзімнің физикалық жағдайыма соншалық алаңдаймын, басқа ештеңе туралы ойлай алмаймын.\"]},\n {ru:[\"Я не заметил, что в последнее время изменился мой интерес к противоположному полу.\",\"Мой интерес к противоположному полу меньше, чем обычно.\",\"Сейчас меня значительно меньше интересует противоположный пол.\",\"Я полностью утратил интерес к этой сфере.\"],\n  kz:[\"Соңғы уақытта менің қарама-қарсы жынысқа деген қызығушылығымның өзгергенін байқамадым.\",\"Менің бұл салаға қызығушылығым бұрынғыдан аз.\",\"Қазір бұл сала мені әлдеқайда аз қызықтырады.\",\"Мен бұл салаға деген қызығушылықты мүлдем жоғалттым.\"]},\n];\n\n/* ================= ЛОКАЛИЗАЦИЯ UI ================= */\nconst T = {\n brand_sub:{ru:\"Психологическая служба\",kz:\"Психологиялық қызмет\"},\n back:{ru:\"Назад\",kz:\"Артқа\"}, next:{ru:\"Далее\",kz:\"Келесі\"},\n wl_eyebrow:{ru:\"Almaty Clinic · двухэтапный скрининг\",kz:\"Almaty Clinic · екі кезеңдік скрининг\"},\n wl_title:{ru:\"Оценка тревоги и депрессии у студентов\",kz:\"Студенттердегі мазасыздық пен депрессияны бағалау\"},\n wl_lead:{ru:\"Первый этап — шкала HADS. Если по шкале тревоги или депрессии набрано 9 баллов и более, автоматически подключается второй этап — шкала депрессии Бека.\",kz:\"Бірінші кезең — HADS шкаласы. Егер мазасыздық немесе депрессия шкаласы бойынша 9 және одан көп ұпай жиналса, екінші кезең — Бек депрессия шкаласы автоматты түрде қосылады.\"},\n wl_qr:{ru:\"Вход выполнен по QR-коду. Тестирование анонимно для других студентов; результаты видит только психолог.\",kz:\"Кіру QR-код арқылы жүзеге асты. Тестілеу басқа студенттер үшін анонимді; нәтижелерді тек психолог көреді.\"},\n wl_start:{ru:\"Начать тестирование\",kz:\"Тестілеуді бастау\"},\n wl_doctor:{ru:\"Кабинет психолога\",kz:\"Психолог кабинеті\"},\n wl_showqr:{ru:\"Показать QR для входа\",kz:\"Кіру үшін QR көрсету\"},\n qr_eyebrow:{ru:\"Вход по QR\",kz:\"QR арқылы кіру\"},\n qr_title:{ru:\"Наведите камеру телефона на код\",kz:\"Телефон камерасын кодқа бағыттаңыз\"},\n qr_lead:{ru:\"Код ведёт на адрес этого приложения. Покажите его студентам (на экране или распечатайте) — они сканируют камерой и попадают на тест.\",kz:\"Код осы қосымшаның мекенжайына апарады. Оны студенттерге көрсетіңіз (экранда немесе басып шығарыңыз) — олар камерамен сканерлеп, тестке өтеді.\"},\n wl_foot:{ru:\"Инструмент скрининга. Не является клиническим диагнозом — интерпретирует специалист.\",kz:\"Скрининг құралы. Клиникалық диагноз емес — маман түсіндіреді.\"},\n rg_eyebrow:{ru:\"Идентификация\",kz:\"Сәйкестендіру\"}, rg_title:{ru:\"Ваши данные\",kz:\"Сіздің деректеріңіз\"},\n rg_lead:{ru:\"Данные нужны психологу для обратной связи. Заполните все поля.\",kz:\"Деректер психологқа кері байланыс үшін қажет. Барлық өрісті толтырыңыз.\"},\n rg_vuz:{ru:\"ВУЗ\",kz:\"ЖОО\"}, rg_vuz_ph:{ru:\"Название учебного заведения\",kz:\"Оқу орнының атауы\"},\n rg_fio:{ru:\"ФИО\",kz:\"Т.А.Ә.\"}, rg_fio_ph:{ru:\"Фамилия Имя Отчество\",kz:\"Тегі Аты Әкесінің аты\"},\n rg_iin:{ru:\"ИИН\",kz:\"ЖСН\"}, rg_iin_hint:{ru:\"Индивидуальный идентификационный номер — 12 цифр.\",kz:\"Жеке сәйкестендіру нөмірі — 12 сан.\"},\n rg_iin_err:{ru:\"ИИН должен содержать ровно 12 цифр\",kz:\"ЖСН дәл 12 саннан тұруы керек\"},\n rg_req:{ru:\"Заполните поле\",kz:\"Өрісті толтырыңыз\"},\n cn_eyebrow:{ru:\"Согласие\",kz:\"Келісім\"}, cn_title:{ru:\"Согласие на обработку данных и тестирование\",kz:\"Деректерді өңдеуге және тестілеуге келісім\"},\n cn_body:{ru:\"Я даю согласие на сбор, хранение и обработку моих персональных данных (ВУЗ, ФИО, ИИН) в целях психологического сопровождения. Оператором персональных данных выступает Almaty Clinic. Данные не передаются третьим лицам без моего согласия, за исключением случаев, предусмотренных законодательством Республики Казахстан. Я подтверждаю, что ознакомлен(а) с целью тестирования и прохожу его добровольно.\",kz:\"Мен психологиялық сүйемелдеу мақсатында жеке деректерімді (ЖОО, Т.А.Ә., ЖСН) жинауға, сақтауға және өңдеуге келісім беремін. Дербес деректер операторы — Almaty Clinic. Деректер Қазақстан Республикасының заңнамасында көзделген жағдайлардан басқа, менің келісімімсіз үшінші тұлғаларға берілмейді. Тестілеу мақсатымен таныстым және оны ерікті түрде өтемін.\"},\n cn_c1:{ru:\"Согласие на сбор, хранение и обработку персональных данных\",kz:\"Жеке деректерді жинауға, сақтауға және өңдеуге келісім\"},\n cn_c2:{ru:\"Согласие на прохождение психологического тестирования\",kz:\"Психологиялық тестілеуден өтуге келісім\"},\n cn_start:{ru:\"Приступить к тесту\",kz:\"Тестті бастау\"},\n dep_stage:{ru:\"HADS · Этап 1\",kz:\"HADS · 1-кезең\"}, beck_stage:{ru:\"Бек · Этап 2\",kz:\"Бек · 2-кезең\"},\n sec_dep:{ru:\"Часть I · Депрессия\",kz:\"I бөлім · Депрессия\"}, sec_anx:{ru:\"Часть II · Тревога\",kz:\"II бөлім · Мазасыздық\"},\n beck_instr:{ru:\"Выберите утверждение, которое ближе всего описывает ваше состояние на этой неделе и сегодня.\",kz:\"Осы аптада және бүгін жағдайыңызды дәл сипаттайтын мәлімдемені таңдаңыз.\"},\n rs_finish:{ru:\"Завершить\",kz:\"Аяқтау\"},\n rs_thanks:{ru:\"Спасибо, тестирование завершено\",kz:\"Рақмет, тестілеу аяқталды\"},\n rs_saved:{ru:\"Результат сохранён для психолога.\",kz:\"Нәтиже психолог үшін сақталды.\"},\n rs_anx:{ru:\"Тревога (HADS)\",kz:\"Мазасыздық (HADS)\"}, rs_dep:{ru:\"Депрессия (HADS)\",kz:\"Депрессия (HADS)\"},\n rs_beck:{ru:\"Депрессия (Бек)\",kz:\"Депрессия (Бек)\"}, rs_pts:{ru:\"баллов\",kz:\"ұпай\"},\n rs_stage2:{ru:\"Пройден 2 этап — шкала Бека\",kz:\"2-кезең өтті — Бек шкаласы\"},\n rs_nostage2:{ru:\"2 этап не потребовался\",kz:\"2-кезең қажет болмады\"},\n note_flag:{ru:\"Рекомендуем в ближайшее время обратиться к психологу Almaty Clinic — по результатам показана консультация специалиста.\",kz:\"Жақын арада Almaty Clinic психологына жүгінуді ұсынамыз — нәтиже бойынша маман кеңесі көрсетілген.\"},\n note_risk:{ru:\"Важно: если у вас есть мысли о причинении себе вреда, не оставайтесь с этим наедине. Обратитесь к психологу немедленно, а в экстренной ситуации звоните 103.\",kz:\"Маңызды: егер өзіңізге зиян келтіру туралы ойларыңыз болса, бұнымен жалғыз қалмаңыз. Дереу психологқа жүгініңіз, ал төтенше жағдайда 103 нөміріне қоңырау шалыңыз.\"},\n note_ok:{ru:\"Выраженных признаков не выявлено. При необходимости вы всегда можете обратиться к психологу.\",kz:\"Айқын белгілер анықталмады. Қажет болса, психологқа әрдайым жүгіне аласыз.\"},\n dc_eyebrow:{ru:\"Служебный раздел\",kz:\"Қызметтік бөлім\"}, dc_title:{ru:\"Кабинет психолога\",kz:\"Психолог кабинеті\"},\n dc_total:{ru:\"Всего\",kz:\"Барлығы\"}, dc_stage2:{ru:\"На 2 этапе\",kz:\"2-кезеңде\"}, dc_flag:{ru:\"Требуют внимания\",kz:\"Назар аудару\"},\n dc_records:{ru:\"Записи\",kz:\"Жазбалар\"}, dc_exit:{ru:\"Выйти\",kz:\"Шығу\"},\n dc_clear:{ru:\"Очистить все записи\",kz:\"Барлық жазбаны тазалау\"},\n dc_qr:{ru:\"QR-код для входа\",kz:\"Кіруге арналған QR-код\"},\n dc_qr_lead:{ru:\"Разместите приложение на хостинге и покажите этот код студентам — он ведёт на текущий адрес страницы.\",kz:\"Қосымшаны хостингке орналастырып, осы кодты студенттерге көрсетіңіз — ол ағымдағы бетке апарады.\"},\n dc_empty:{ru:\"Пока нет ни одной записи.\",kz:\"Әзірге бірде-бір жазба жоқ.\"},\n dc_pin:{ru:\"Введите пароль психолога:\",kz:\"Психолог паролін енгізіңіз:\"},\n confirm_clear:{ru:\"Удалить все сохранённые результаты? Действие необратимо.\",kz:\"Барлық сақталған нәтижені жою керек пе? Әрекет қайтарылмайды.\"},\n};\n/* Оценка/интерпретация */\nconst I = {\n hads_norm:{ru:\"норма\",kz:\"қалыпты\"}, hads_sub:{ru:\"субклинически выраженная\",kz:\"субклиникалық деңгей\"}, hads_clin:{ru:\"клинически выраженная\",kz:\"клиникалық деңгей\"},\n b_none:{ru:\"отсутствие депрессии / ремиссия\",kz:\"депрессия жоқ / ремиссия\"}, b_border:{ru:\"пограничное состояние\",kz:\"шекаралық жағдай\"},\n b_mild:{ru:\"лёгкая депрессия\",kz:\"жеңіл депрессия\"}, b_mod:{ru:\"депрессия средней тяжести\",kz:\"орташа депрессия\"}, b_sev:{ru:\"тяжёлая депрессия\",kz:\"ауыр депрессия\"},\n};\n\n/* ================= СОСТОЯНИЕ ================= */\nlet lang='ru';\nlet session=null;        // текущий проходящий\nlet queue=[];            // список вопросов текущего этапа\nlet phase='hads';        // 'hads' | 'beck'\nlet idx=0;\nlet records=[];          // все записи (кэш / локальный режим)\nconst DOCTOR_PIN='0000'; // резервный PIN, если сервер недоступен (превью)\nconst STORE_KEY='psy_screening_records_v1';\n\n/* ---- Работа с бэкендом ----\n   API_BASE='' → тот же адрес, что и страница (сервер отдаёт и фронтенд, и /api).\n   Все вызовы обёрнуты в try/catch: если сервера нет (превью), включается\n   локальный режим, чтобы приложение оставалось работоспособным. */\nconst API_BASE='';\nlet adminToken=null;   // токен психолога после входа\nlet apiOnline=false;   // true после успешного обращения к серверу\n\nasync function apiSubmit(rec){\n  const res=await fetch(API_BASE+'/api/records',{method:'POST',\n    headers:{'Content-Type':'application/json'},body:JSON.stringify(rec)});\n  if(!res.ok) throw new Error('submit failed');\n  return true;\n}\nasync function apiLogin(password){\n  const res=await fetch(API_BASE+'/api/login',{method:'POST',\n    headers:{'Content-Type':'application/json'},body:JSON.stringify({password})});\n  if(!res.ok) return false;\n  const j=await res.json(); adminToken=j.token; return true;\n}\nasync function apiList(){\n  const res=await fetch(API_BASE+'/api/records',{headers:{Authorization:'Bearer '+adminToken}});\n  if(!res.ok) throw new Error('list failed');\n  return await res.json();\n}\nasync function apiClear(){\n  await fetch(API_BASE+'/api/records',{method:'DELETE',headers:{Authorization:'Bearer '+adminToken}});\n}\n\n/* Локальный кэш (резерв для превью без сервера) */\nfunction loadRecords(){ try{const r=localStorage.getItem(STORE_KEY);records=r?JSON.parse(r):[];}catch(e){records=records||[];} }\nfunction saveRecords(){ try{localStorage.setItem(STORE_KEY,JSON.stringify(records));}catch(e){/* превью: в памяти */} }\n\n/* ================= ЯЗЫК ================= */\nfunction setLang(l){\n  lang=l;\n  document.getElementById('lang-ru').classList.toggle('on',l==='ru');\n  document.getElementById('lang-kz').classList.toggle('on',l==='kz');\n  document.documentElement.lang = l==='kz'?'kk':'ru';\n  document.querySelectorAll('[data-t]').forEach(el=>{const k=el.getAttribute('data-t'); if(T[k]) el.textContent=T[k][l];});\n  document.querySelectorAll('[data-tph]').forEach(el=>{const k=el.getAttribute('data-tph'); if(T[k]) el.placeholder=T[k][l];});\n  if(document.getElementById('s-test').classList.contains('active')) renderQ();\n  if(document.getElementById('s-result').classList.contains('active')) renderResult();\n  if(document.getElementById('s-doctor').classList.contains('active')) renderDoctor();\n}\n\n/* ================= НАВИГАЦИЯ ================= */\nfunction go(name){\n  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));\n  document.getElementById('s-'+name).classList.add('active');\n  window.scrollTo({top:0,behavior:'instant'});\n}\n\n/* ================= РЕГИСТРАЦИЯ ================= */\nfunction submitRegister(){\n  const vuz=document.getElementById('in-vuz').value.trim();\n  const fio=document.getElementById('in-fio').value.trim();\n  const iin=document.getElementById('in-iin').value.trim();\n  let ok=true;\n  toggleBad('f-vuz', !vuz); if(!vuz) ok=false;\n  toggleBad('f-fio', !fio); if(!fio) ok=false;\n  const iinOk=/^\\d{12}$/.test(iin); toggleBad('f-iin', !iinOk); if(!iinOk) ok=false;\n  if(!ok) return;\n  session={vuz,fio,iin,lang,ts:new Date()};\n  go('consent');\n}\nfunction toggleBad(id,bad){document.getElementById(id).classList.toggle('bad',bad);}\n\n/* ================= СОГЛАСИЕ ================= */\nfunction toggleChk(n){\n  const cb=document.getElementById('chk'+n);\n  // нормализуем состояние (клик мог прийти с label или с input)\n  setTimeout(()=>{\n    document.getElementById('chk'+n+'-wrap').classList.toggle('on',cb.checked);\n    const both=document.getElementById('chk1').checked && document.getElementById('chk2').checked;\n    document.getElementById('consent-next').disabled=!both;\n  },0);\n}\n\n/* ================= ТЕСТ ================= */\nfunction startTest(){\n  phase='hads'; idx=0;\n  // HADS: сначала депрессия, потом тревога — с пометкой шкалы\n  queue = HADS_DEP.map((it,i)=>({type:'hads',scale:'dep',i,it}))\n        .concat(HADS_ANX.map((it,i)=>({type:'hads',scale:'anx',i,it})));\n  session.hads={dep:new Array(7).fill(null),anx:new Array(7).fill(null)};\n  session.beck=null;\n  go('test'); renderQ();\n}\nfunction startBeck(){\n  phase='beck'; idx=0;\n  queue = BECK.map((it,i)=>({type:'beck',i,it}));\n  session.beck={answers:new Array(21).fill(null)};\n  renderQ();\n}\n\nfunction currentAnswer(){\n  const q=queue[idx];\n  if(q.type==='hads') return session.hads[q.scale][q.i];\n  return session.beck.answers[q.i];\n}\nfunction setAnswer(val){\n  const q=queue[idx];\n  if(q.type==='hads') session.hads[q.scale][q.i]=val;\n  else session.beck.answers[q.i]=val;\n  document.getElementById('q-next').disabled=false;\n  document.querySelectorAll('#q-card .opt').forEach(el=>{\n    el.classList.toggle('on', +el.dataset.val===val);\n  });\n}\n\nfunction renderQ(){\n  const q=queue[idx];\n  const total=queue.length;\n  const stageLabel = phase==='hads'?T.dep_stage[lang]:T.beck_stage[lang];\n  document.getElementById('stage-label').textContent=stageLabel;\n  document.getElementById('q-counter').textContent=(idx+1)+' / '+total;\n  document.getElementById('pbar-fill').style.width=((idx+1)/total*100)+'%';\n\n  const card=document.getElementById('q-card');\n  let html='';\n  if(q.type==='hads'){\n    const sec = q.scale==='dep'?T.sec_dep[lang]:T.sec_anx[lang];\n    html+='<div class=\"qnum\">'+sec+' · '+(q.i+1)+'/7</div>';\n    html+='<div class=\"qtext\">'+q.it.q[lang]+'</div>';\n    const cur=currentAnswer();\n    q.it.o.forEach(o=>{\n      html+='<div class=\"opt'+(cur===o.s?' on':'')+'\" data-val=\"'+o.s+'\" onclick=\"setAnswer('+o.s+')\"><span class=\"radio\"></span><span class=\"otxt\">'+o[lang]+'</span></div>';\n    });\n  } else {\n    html+='<div class=\"qnum\">'+T.beck_stage[lang]+' · '+(q.i+1)+'/21</div>';\n    html+='<div class=\"qtext\">'+T.beck_instr[lang]+'</div>';\n    const cur=currentAnswer();\n    q.it[lang].forEach((txt,s)=>{\n      html+='<div class=\"opt'+(cur===s?' on':'')+'\" data-val=\"'+s+'\" onclick=\"setAnswer('+s+')\"><span class=\"radio\"></span><span class=\"otxt\">'+txt+'</span></div>';\n    });\n  }\n  card.innerHTML=html;\n\n  document.getElementById('q-next').disabled = currentAnswer()===null;\n  document.getElementById('q-back').style.visibility = idx===0 ? 'hidden':'visible';\n  const isLast = idx===queue.length-1;\n  document.getElementById('q-next').textContent = isLast\n     ? (phase==='hads' ? T.next[lang] : T.rs_finish[lang])\n     : T.next[lang];\n}\n\nfunction prevQ(){ if(idx>0){idx--; renderQ(); window.scrollTo({top:0});} }\nfunction nextQ(){\n  if(currentAnswer()===null) return;\n  if(idx<queue.length-1){ idx++; renderQ(); window.scrollTo({top:0}); return; }\n  // Конец этапа\n  if(phase==='hads'){\n    const dep=sum(session.hads.dep), anx=sum(session.hads.anx);\n    session.hadsScore={dep,anx};\n    if(dep>=HADS_STAGE2_THRESHOLD || anx>=HADS_STAGE2_THRESHOLD){\n      session.stage2=true; startBeck(); window.scrollTo({top:0});\n    } else {\n      session.stage2=false; finalize();\n    }\n  } else {\n    session.beckScore=sum(session.beck.answers);\n    session.beckItem9=session.beck.answers[8]||0;\n    finalize();\n  }\n}\nfunction sum(a){return a.reduce((x,y)=>x+(y||0),0);}\n\n/* ================= ИНТЕРПРЕТАЦИЯ ================= */\nfunction hadsInterp(v){ if(v<=7)return{key:'hads_norm',color:'var(--calm)'}; if(v<=10)return{key:'hads_sub',color:'var(--amber)'}; return{key:'hads_clin',color:'var(--clay)'}; }\nfunction beckInterp(v){\n  if(v<=9)return{key:'b_none',color:'var(--calm)'};\n  if(v<=13)return{key:'b_border',color:'var(--amber)'};\n  if(v<=19)return{key:'b_mild',color:'var(--amber)'};\n  if(v<=28)return{key:'b_mod',color:'var(--clay)'};\n  return{key:'b_sev',color:'var(--clay)'};\n}\n\n/* ================= ФИНАЛ / СОХРАНЕНИЕ ================= */\nasync function finalize(){\n  const dep=session.hadsScore.dep, anx=session.hadsScore.anx;\n  const rec={\n    ts:new Date().toISOString(),\n    vuz:session.vuz, fio:session.fio, iin:session.iin, lang:session.lang,\n    hadsAnx:anx, hadsDep:dep,\n    hadsAnxI:hadsInterp(anx).key, hadsDepI:hadsInterp(dep).key,\n    stage2:!!session.stage2,\n    beck: session.stage2? session.beckScore : null,\n    beckI: session.stage2? beckInterp(session.beckScore).key : null,\n    beckItem9: session.stage2? (session.beckItem9||0):0,\n  };\n  rec.flag = (anx>=11 || dep>=11 || (rec.beck!==null && rec.beck>19) || rec.beckItem9>0);\n  session._rec=rec;\n  renderResult(); go('result');   // показываем результат сразу\n  // сохраняем: сначала на сервер, при неудаче — локально\n  try{ await apiSubmit(rec); apiOnline=true; }\n  catch(e){ records.push(rec); saveRecords(); }\n}\n\nfunction renderResult(){\n  const r=session&&session._rec; if(!r)return;\n  const head=document.getElementById('result-head');\n  head.innerHTML='<span class=\"eyebrow\" style=\"color:var(--sage)\">✓</span>'+\n    '<h2 style=\"margin-top:8px\">'+T.rs_thanks[lang]+'</h2>'+\n    '<p class=\"muted\">'+T.rs_saved[lang]+'</p>';\n\n  const det=document.getElementById('result-detail');\n  let html='';\n  html+=resultRow(T.rs_anx[lang], r.hadsAnx, 21, hadsInterp(r.hadsAnx));\n  html+=resultRow(T.rs_dep[lang], r.hadsDep, 21, hadsInterp(r.hadsDep));\n  if(r.stage2){\n    html+='<div style=\"height:8px\"></div>';\n    html+=resultRow(T.rs_beck[lang], r.beck, 63, beckInterp(r.beck));\n  }\n  // статус этапа 2\n  html+='<div class=\"notice calm\" style=\"margin-top:16px\"><div class=\"ntxt\">'+\n        (r.stage2?('▸ '+T.rs_stage2[lang]):('✓ '+T.rs_nostage2[lang]))+'</div></div>';\n  // рекомендации\n  if(r.beckItem9>0){\n    html+='<div class=\"notice\"><div class=\"ntxt\"><strong>'+T.note_risk[lang]+'</strong></div></div>';\n  } else if(r.flag){\n    html+='<div class=\"notice\"><div class=\"ntxt\">'+T.note_flag[lang]+'</div></div>';\n  } else {\n    html+='<div class=\"notice calm\"><div class=\"ntxt\">'+T.note_ok[lang]+'</div></div>';\n  }\n  det.innerHTML=html;\n}\n\nfunction resultRow(label, val, max, interp){\n  const pct=Math.min(100, val/max*100);\n  // сегменты шкалы\n  let segs;\n  if(max===21){ segs=[[7,'var(--calm)'],[10,'var(--amber)'],[21,'var(--clay)']]; }\n  else { segs=[[9,'var(--calm)'],[13,'var(--amber)'],[19,'var(--amber)'],[28,'var(--clay)'],[63,'var(--clay)']]; }\n  let prev=0, track='';\n  segs.forEach(([end,c])=>{ track+='<span style=\"width:'+((end-prev)/max*100)+'%;background:'+c+'\"></span>'; prev=end; });\n  return '<div class=\"resultrow\"><div>'+\n    '<div class=\"lbl\">'+label+'</div>'+\n    '<div class=\"pill\" style=\"color:'+interp.color+';background:color-mix(in srgb,'+interp.color+' 14%,#fff)\">'+I[interp.key][lang]+'</div>'+\n    '</div><div style=\"text-align:right;min-width:56px\"><span class=\"bignum\" style=\"color:'+interp.color+'\">'+val+'</span>'+\n    '<div class=\"sub\">/ '+max+' '+T.rs_pts[lang]+'</div></div></div>'+\n    '<div class=\"gauge\"><div class=\"track\">'+track+'<span class=\"marker\" style=\"left:'+pct+'%\"></span></div></div>';\n}\n\nfunction finishToWelcome(){ session=null; go('welcome'); }\n\n/* ================= КАБИНЕТ ПСИХОЛОГА ================= */\nasync function openDoctor(){\n  const pass=prompt(T.dc_pin[lang], '');\n  if(pass===null) return;\n  // Основной путь — вход через сервер\n  let ok=false;\n  try{ ok=await apiLogin(pass); }catch(e){ ok=false; }\n  if(ok){ apiOnline=true; await renderDoctor(); go('doctor'); makeQR(); return; }\n  // Резерв — локальный PIN (когда сервер недоступен, напр. в превью)\n  if(pass===DOCTOR_PIN){ adminToken=null; apiOnline=false; await renderDoctor(); go('doctor'); makeQR(); return; }\n  alert(lang==='kz'?'Пароль қате ✗':'Неверный пароль ✗');\n}\nasync function renderDoctor(){\n  // В серверном режиме тянем записи из базы, иначе — локальный кэш\n  if(adminToken){ try{ records=await apiList(); apiOnline=true; }catch(e){ loadRecords(); } }\n  else { loadRecords(); }\n  const total=records.length;\n  const s2=records.filter(r=>r.stage2).length;\n  const fl=records.filter(r=>r.flag).length;\n  document.getElementById('st-total').textContent=total;\n  document.getElementById('st-stage2').textContent=s2;\n  document.getElementById('st-flag').textContent=fl;\n\n  const box=document.getElementById('doc-table');\n  if(!total){ box.innerHTML='<div class=\"empty\">'+T.dc_empty[lang]+'</div>'; return; }\n  let rows='';\n  records.slice().reverse().forEach(r=>{\n    const d=new Date(r.ts);\n    const dt=d.toLocaleDateString('ru-RU')+' '+d.toLocaleTimeString('ru-RU',{hour:'2-digit',minute:'2-digit'});\n    const beckCell = r.stage2 ? (r.beck+' · '+I[r.beckI][lang]) : '—';\n    const tag = r.flag? '<span class=\"tag\" style=\"background:#f7e0da;color:var(--clay)\">!</span>' : '<span class=\"tag\" style=\"background:#dcefe6;color:var(--calm)\">ok</span>';\n    rows+='<tr><td>'+tag+'</td><td>'+dt+'</td><td>'+esc(r.fio)+'</td><td>'+esc(r.vuz)+'</td><td>'+r.iin+'</td>'+\n      '<td>'+r.hadsAnx+'</td><td>'+r.hadsDep+'</td><td>'+(r.stage2?'✓':'—')+'</td><td>'+beckCell+'</td></tr>';\n  });\n  box.innerHTML='<div class=\"tablewrap\"><table><thead><tr>'+\n    '<th>·</th><th>Дата</th><th>ФИО</th><th>ВУЗ</th><th>ИИН</th><th>HADS-Т</th><th>HADS-Д</th><th>2 эт.</th><th>Бек</th>'+\n    '</tr></thead><tbody>'+rows+'</tbody></table></div>';\n}\nfunction esc(s){return String(s).replace(/[<>&]/g,c=>({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]));}\n\nfunction makeQR(){\n  const box=document.getElementById('qrbox'); box.innerHTML='';\n  try{ new QRCode(box,{text:location.href.split('#')[0],width:180,height:180,colorDark:'#0A4D45',colorLight:'#ffffff'}); }\n  catch(e){ box.innerHTML='<div class=\"muted\">'+location.href+'</div>'; }\n}\n\nfunction showEntryQR(){\n  go('qr');\n  const url=location.origin && location.origin!=='null' ? location.origin : location.href.split('#')[0];\n  const box=document.getElementById('entry-qrbox'); box.innerHTML='';\n  document.getElementById('entry-qr-url').textContent=url;\n  try{ new QRCode(box,{text:url,width:220,height:220,colorDark:'#0A4D45',colorLight:'#ffffff'}); }\n  catch(e){ box.innerHTML='<div class=\"muted\">'+url+'</div>'; }\n}\n\nasync function clearAll(){\n  if(!confirm(T.confirm_clear[lang])) return;\n  if(adminToken && apiOnline){ try{ await apiClear(); }catch(e){} }\n  else { records=[]; saveRecords(); }\n  await renderDoctor();\n}\n\n/* ================= ВЫГРУЗКА В EXCEL ================= */\nasync function exportExcel(){\n  // Серверный режим: скачиваем готовый файл из базы\n  if(adminToken && apiOnline){\n    try{\n      const res=await fetch(API_BASE+'/api/export.xlsx',{headers:{Authorization:'Bearer '+adminToken}});\n      if(!res.ok) throw new Error('export');\n      const blob=await res.blob(), url=URL.createObjectURL(blob);\n      const a=document.createElement('a');\n      a.href=url; a.download='almaty_clinic_skrining_'+new Date().toISOString().slice(0,10)+'.xlsx';\n      document.body.appendChild(a); a.click(); a.remove(); URL.revokeObjectURL(url);\n      return;\n    }catch(e){ /* перейдём к локальной генерации */ }\n  }\n  // Локальный режим: генерируем на клиенте из текущих записей\n  const rows=records.map((r,i)=>({\n    '№':i+1,\n    'Дата и время':new Date(r.ts).toLocaleString('ru-RU'),\n    'ВУЗ':r.vuz, 'ФИО':r.fio, 'ИИН':r.iin,\n    'Язык':r.lang==='kz'?'каз':'рус',\n    'HADS Тревога (балл)':r.hadsAnx, 'HADS Тревога':I[r.hadsAnxI].ru,\n    'HADS Депрессия (балл)':r.hadsDep, 'HADS Депрессия':I[r.hadsDepI].ru,\n    'Направлен на 2 этап':r.stage2?'да':'нет',\n    'Бек (балл)':r.stage2?r.beck:'', 'Бек интерпретация':r.stage2?I[r.beckI].ru:'',\n    'Отметка риска (п.9 Бек)':r.beckItem9>0?'да':'',\n    'Требует внимания':r.flag?'да':'',\n  }));\n  if(!rows.length){ alert(T.dc_empty[lang]); return; }\n  const ws=XLSX.utils.json_to_sheet(rows);\n  ws['!cols']=[{wch:4},{wch:18},{wch:24},{wch:26},{wch:14},{wch:6},{wch:14},{wch:22},{wch:16},{wch:22},{wch:16},{wch:9},{wch:24},{wch:16},{wch:14}];\n  const wb=XLSX.utils.book_new();\n  XLSX.utils.book_append_sheet(wb,ws,'Результаты');\n  const stamp=new Date().toISOString().slice(0,10);\n  XLSX.writeFile(wb,'skrining_'+stamp+'.xlsx');\n}\n\n/* ================= ИНИЦИАЛИЗАЦИЯ ================= */\nloadRecords();\nsetLang('ru');\n// вход через QR: поддержка ?lang=kz\nconst p=new URLSearchParams(location.search);\nif(p.get('lang')==='kz') setLang('kz');\n</script>\n</body>\n</html>\n";
